const fetchData = require("../utils/fetchData");

async function getMemberDetail(apiKey, memberId) {
  const url = `https://api.jkt48connect.my.id/api/member/${memberId}?api_key=${apiKey}`;
  const response = await fetchData(url);
  return response;
}

async function getAllMembers(apiKey) {
  const url = `https://api.jkt48connect.my.id/api/member?api_key=${apiKey}`;
  const response = await fetchData(url);
  return response;
}

async function getBirthdayMembers(apiKey) {
  const url = `https://api.jkt48connect.my.id/api/next-birthday?api_key=${apiKey}`;
  const response = await fetchData(url);
  return response;
}

module.exports = { getMemberDetail, getAllMembers, getBirthdayMembers };